import{c as a,Q as o,j as n,m as s}from"./chunks/framework.Bhbi9jCp.js";const h=JSON.parse('{"title":"AI 与村民:寻路、Brain 与交易袭击","description":"","frontmatter":{},"headers":[],"relativePath":"minecraftLearning/23-AI与村民-寻路Brain与交易袭击.md","filePath":"minecraftLearning/23-AI与村民-寻路Brain与交易袭击.md","lastUpdated":1781677803000}'),r={name:"minecraftLearning/23-AI与村民-寻路Brain与交易袭击.md"};function i(e,t,l,p,d,g){return o(),n("div",null,[...t[0]||(t[0]=[s(`<h1 id="ai-与村民-寻路、brain-与交易袭击" tabindex="-1">AI 与村民:寻路、Brain 与交易袭击 <a class="header-anchor" href="#ai-与村民-寻路、brain-与交易袭击" aria-label="Permalink to &quot;AI 与村民:寻路、Brain 与交易袭击&quot;">​</a></h1><p>第 06 篇讲实体时,AI 那块只点了两个词:A* 和 Brain。但实体 AI 是整个服务端里<strong>最容易写出 lag、又最被低估</strong>的一块——一只僵尸看起来只是朝你走过来,背后是寻路、目标仲裁、感知扫描三套东西每 tick 在跑。村民更夸张,它几乎是一个塞进方块世界里的小型 agent:有记忆、有作息、有经济、有声望。这篇就把这层拆开。</p><blockquote><p>一句话先记住:<strong>Minecraft 有两套并存的 AI 架构——老的 Goal 是&quot;优先级抢占的动作列表&quot;,新的 Brain 是&quot;记忆+感知+活动驱动的行为系统&quot;;村民是 Brain 系统的极致样板,贵也贵在这。</strong> 而寻路是它们共同的、最烧 CPU 的底层服务。</p></blockquote><hr><h2 id="一、寻路-每一步都不便宜" tabindex="-1">一、寻路:每一步都不便宜 <a class="header-anchor" href="#一、寻路-每一步都不便宜" aria-label="Permalink to &quot;一、寻路:每一步都不便宜&quot;">​</a></h2><p>怪物要&quot;走向&quot;目标,靠的是经典 A*,但它跑在一张<strong>临时现算的节点图</strong>上,而不是预存的导航网格。</p><p>流程大致是:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>给定起点和目标</span></span>
<span class="line"><span>  → NodeEvaluator 在周围按需展开节点(每个节点≈一个可站立的方块位置)</span></span>
<span class="line"><span>  → 给每个节点判类型 PathType + 通行代价 malus</span></span>
<span class="line"><span>  → A* 用 f = g + h 找代价最低路径</span></span>
<span class="line"><span>  → 得到一串路点 Path,实体每 tick 朝当前路点移动,走到了就推进下一个</span></span></code></pre></div><p>关键在 <strong>NodeEvaluator + PathType</strong>:它不是简单的&quot;能走/不能走&quot;,而是给不同地形打<strong>代价(malus)</strong>:</p><table tabindex="0"><thead><tr><th>PathType</th><th>行为</th></tr></thead><tbody><tr><td>WALKABLE</td><td>正常,代价 0</td></tr><tr><td>WATER / LAVA</td><td>高代价或禁止(怕水的怪 malus 很高,直接绕)</td></tr><tr><td>DANGER_FIRE / DAMAGE_FIRE</td><td>火、岩浆边缘,尽量躲</td></tr><tr><td>FENCE / DOOR_WOOD_CLOSED</td><td>栅栏当墙、关着的木门可开</td></tr><tr><td>OPEN</td><td>悬空(下方是洞),通常禁止,避免走下悬崖</td></tr></tbody></table><p>代价的意义在于:寻路不是只看&quot;通不通&quot;,而是<strong>带偏好地绕</strong>——所以怕水的怪会沿岸走、铁傀儡会避开仙人掌。</p><p><strong>为什么它贵?</strong> A* 的开销随搜索空间膨胀,而 Minecraft 的&quot;图&quot;是 3D 的、按需展开的。一旦目标够不着(隔着墙、隔着深坑),搜索会扩展大量节点才放弃。所以:</p><ul><li>寻路有<strong>节点数上限</strong>(够不着时提前放弃,避免单次寻路炸 tick);</li><li>实体不是每 tick 重算整条路,而是<strong>复用现有 Path</strong>,只在必要时(目标移动、被挡住)重算;</li><li>但<strong>一大群怪同时寻路</strong>(刷怪塔、村庄被围)依然是 tick 时间的大头——这正好接上第 19 篇&quot;掉 TPS 来源&quot;里说的实体开销,寻路是其中最尖的那根刺。</li></ul><hr><h2 id="二、两套-ai-架构-goal-vs-brain" tabindex="-1">二、两套 AI 架构:Goal vs Brain <a class="header-anchor" href="#二、两套-ai-架构-goal-vs-brain" aria-label="Permalink to &quot;二、两套 AI 架构:Goal vs Brain&quot;">​</a></h2><p>Minecraft 历史上攒了<strong>两套并存</strong>的 AI 框架,新怪和旧怪各用各的,理解这点能解释很多&quot;为什么村民比僵尸卡&quot;。</p><h3 id="老派-goal-系统-goalselector" tabindex="-1">老派:Goal 系统(GoalSelector) <a class="header-anchor" href="#老派-goal-系统-goalselector" aria-label="Permalink to &quot;老派:Goal 系统(GoalSelector)&quot;">​</a></h3><p>僵尸、骷髅、苦力怕这些&quot;老怪&quot;用的是 <strong>Goal</strong>:</p><ul><li>一个实体挂一组 <strong>Goal</strong>(浮空、追玩家、随机闲逛、躲太阳……),每个 Goal 带<strong>优先级</strong>和<strong>互斥标志</strong>(占用 移动/视线/跳跃 哪些&quot;控制通道&quot;)。</li><li>每 tick,<strong>GoalSelector</strong> 扫一遍:按优先级看哪些 Goal 能启动、且不和已运行的高优先级 Goal 抢同一通道。能跑就跑,跑不动的被抢占。</li><li>心智模型:<strong>一张按优先级抢占的&quot;动作清单&quot;</strong>。简单、直接、好加新行为,但状态都散在各个 Goal 里,跨行为共享信息很别扭。</li></ul><h3 id="新派-brain-系统" tabindex="-1">新派:Brain 系统 <a class="header-anchor" href="#新派-brain-系统" aria-label="Permalink to &quot;新派:Brain 系统&quot;">​</a></h3><p>村民、监守者、傀儡、部分新生物用的是 <strong>Brain</strong>,它更像一棵行为树 + 黑板,由四个东西组成:</p><table tabindex="0"><thead><tr><th>部件</th><th>作用</th></tr></thead><tbody><tr><td><strong>Memory(记忆)</strong></td><td>黑板:记住&quot;家在哪、工作站在哪、最近见过的玩家、攻击目标、走到一半的路点&quot;等,有的带过期时间</td></tr><tr><td><strong>Sensor(感知)</strong></td><td>周期性扫描环境,把结果写进 Memory(附近的玩家/生物/兴趣点/可交互方块)</td></tr><tr><td><strong>Behavior(行为)</strong></td><td>读 Memory 决定做什么(走向工作站、睡觉、逃跑、交易)</td></tr><tr><td><strong>Activity(活动)</strong></td><td>行为的分组/状态:CORE/IDLE/WORK/REST/PANIC/RAID……当前处于哪个 Activity 决定哪批 Behavior 生效</td></tr></tbody></table><p>Brain 的运转是:<strong>Sensor 写记忆 → 当前 Activity 选出一批 Behavior → Behavior 读记忆并行动</strong>。比 Goal 强在<strong>状态集中、可共享、可表达复杂的条件切换</strong>(比如&quot;天黑了且有床 → 切到 REST Activity → 跑回家睡觉&quot;)。</p><p><strong>代价就在这。</strong> Brain 每 tick 要跑一圈 Sensor 扫描(感知周围实体、扫 POI)、维护一堆带过期的 Memory、做 Activity 仲裁——比 Goal 那张清单重得多。所以<strong>村民数量一多,Brain 的感知和寻路叠在一起,就是村庄卡顿的主因</strong>。</p><hr><h2 id="三、村民-一个塞进方块世界的小-agent" tabindex="-1">三、村民:一个塞进方块世界的小 agent <a class="header-anchor" href="#三、村民-一个塞进方块世界的小-agent" aria-label="Permalink to &quot;三、村民:一个塞进方块世界的小 agent&quot;">​</a></h2><p>村民是 Brain 系统的极限样板。它身上几乎挂满了前面所有篇章的概念。</p><h3 id="职业绑定工作站-poi" tabindex="-1">职业绑定工作站 = POI <a class="header-anchor" href="#职业绑定工作站-poi" aria-label="Permalink to &quot;职业绑定工作站 = POI&quot;">​</a></h3><p>村民的职业(农民、图书管理员、武器匠……)不是凭空来的,而是<strong>绑定到一个工作站方块</strong>:</p><ul><li>工作站(讲台、酿造台、高炉……)在世界里是一种 <strong>POI(兴趣点)</strong>,存在独立的 <code>poi/</code> region 里(就是第 11 篇提的那个 POI 数据层)。</li><li>无业村民的 Sensor 扫描附近<strong>没被占用的 POI</strong>,写进 Memory,Behavior 据此走过去&quot;认领&quot;工作站,获得职业。</li><li>工作站被破坏 → 失业 → 重新找。这套&quot;找工作站&quot;全程依赖 <strong>POI 的索引与缓存</strong>。</li></ul><blockquote><p>反直觉点:POI 是带缓存/索引的。村民找不到明明就在旁边的工作站,常是因为 POI 没被正确登记或缓存没刷新——这是&quot;村民职业刷不出来&quot;类玄学的工程根源。</p></blockquote><h3 id="一天的作息-schedule" tabindex="-1">一天的作息 = Schedule <a class="header-anchor" href="#一天的作息-schedule" aria-label="Permalink to &quot;一天的作息 = Schedule&quot;">​</a></h3><p>村民按 <strong>Schedule(作息表)</strong> 切 Activity:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>白天早些  → WORK   (去工作站旁边干活、补货)</span></span>
<span class="line"><span>正午      → MEET   (跑到聚会点闲逛、繁殖判定)</span></span>
<span class="line"><span>傍晚      → REST   (回家找床睡觉)</span></span>
<span class="line"><span>夜里      → 睡觉/躲在屋里</span></span>
<span class="line"><span>受威胁    → PANIC / 被袭击时切 RAID 相关</span></span></code></pre></div><p>Schedule 决定当前 Activity,Activity 决定哪批 Behavior 生效——这就是 Brain 四件套的实际编排。</p><h3 id="交易经济-供需-补货" tabindex="-1">交易经济:供需 + 补货 <a class="header-anchor" href="#交易经济-供需-补货" aria-label="Permalink to &quot;交易经济:供需 + 补货&quot;">​</a></h3><p>村民交易不是固定价:</p><ul><li>每种交易有<strong>最大使用次数</strong>,用光就<strong>暂时下架</strong>,村民回工作站<strong>补货</strong>(restock,每天有限次)后恢复。</li><li><strong>供需</strong>:某交易被频繁使用,价格上浮;长期没人买,回落。</li><li>这是一套真实跑在服务端的小经济模型,而不是写死的商店。</li></ul><h3 id="声望与八卦-gossip" tabindex="-1">声望与八卦 gossip <a class="header-anchor" href="#声望与八卦-gossip" aria-label="Permalink to &quot;声望与八卦 gossip&quot;">​</a></h3><p>村民之间会<strong>传播对玩家的看法</strong>:</p><ul><li>你和某村民交易、救过它 → 该村民对你<strong>好感(gossip)上升</strong> → 折扣;伤害村民 → 好感暴跌、价格上涨,甚至触发<strong>铁傀儡敌对</strong>。</li><li>好感会在村民间<strong>扩散</strong>(八卦),所以得罪一个村庄可能整村涨价。</li><li>这套 gossip 是带数值和衰减的,存在村民的 NBT 里——又一处&quot;逐实例数据挂在实体上&quot;的例子(呼应第 06 篇)。</li></ul><hr><h2 id="四、袭击-raid-一个独立的-事件状态-系统" tabindex="-1">四、袭击 raid:一个独立的&quot;事件状态&quot;系统 <a class="header-anchor" href="#四、袭击-raid-一个独立的-事件状态-系统" aria-label="Permalink to &quot;四、袭击 raid:一个独立的&quot;事件状态&quot;系统&quot;">​</a></h2><p>袭击不是某个实体的 AI,而是一个<strong>绑在村庄上的全局事件状态机</strong>(存在世界的 saved data 里,类似第 11 篇说的全局数据层):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>玩家带着&quot;不祥之兆&quot;效果进入有床+工作站的村庄</span></span>
<span class="line"><span>  → 在该村庄中心生成一个 Raid 对象,带波次计数、参与怪物列表、Boss 血条</span></span>
<span class="line"><span>  → 一波波刷出灾厄者(掠夺者/卫道士/唤魔师/劫掠兽)</span></span>
<span class="line"><span>  → 村民躲、铁傀儡防守、玩家清怪</span></span>
<span class="line"><span>  → 全波清完 → 胜利;村民全死/超时 → 失败</span></span></code></pre></div><p>关键点:<strong>Raid 是个有生命周期的事件对象,不是怪物本身</strong>。它独立于参战实体存在,负责调度波次、统计、判定胜负——这和&quot;实体&quot;&quot;方块实体&quot;都不同,更接近第 11 篇里&quot;不绑具体格子的全局世界数据&quot;。</p><hr><h2 id="五、把它接回前面" tabindex="-1">五、把它接回前面 <a class="header-anchor" href="#五、把它接回前面" aria-label="Permalink to &quot;五、把它接回前面&quot;">​</a></h2><ul><li><strong>寻路</strong> 是 AI 的底层服务,贵,直接喂给第 19 篇的&quot;实体是 lag 大头&quot;。</li><li><strong>Goal vs Brain</strong> 解释了为什么不同怪开销差很大;Brain 的 Memory/Sensor/Activity 是&quot;实体身上的小型黑板系统&quot;。</li><li><strong>村民</strong> 把 POI(第 11 篇)、Schedule、经济、gossip 全串起来,几乎是&quot;实体 + 逐实例 NBT + 兴趣点数据层&quot;的集大成。</li><li><strong>袭击</strong> 又是一个&quot;全局事件状态&quot;的例子,提醒你:世界里的逻辑不全在方块和实体上,还有一层不绑坐标的事件/会话状态。</li></ul><p>一句话收尾:<strong>怪物的&quot;智能&quot;本质是每 tick 的寻路 + 仲裁 + 感知;村民只是把这套推到极致,加上记忆、作息和经济,于是它既像 NPC,又是服务端最贵的常驻负载之一。</strong></p>`,50)])])}const c=a(r,[["render",i]]);export{h as __pageData,c as default};
